# Define function to call kong admin API and add Service, Route and Target. Use Service Name, Service ID and Route name as key to create service route target. 
def POSTRequests(SERVICE_ID,ROUTE_ID,SERVICE_NAME,ROUTE_NAME,TARGET):
    
    # Request to Add Service
    serviceRequest = req.request("POST", KONG_URL + 'services', json= SERVICE_NAME)

    # Request to Add Route and configure Service ID 
    routeRequest = req.request('POST',KONG_URL + SERVICE_ID + '/routes',json= ROUTE_NAME,headers={"Content-Type": "application/x-www-form-urlencoded"})
    responseBodyServiceRoute = routeRequest.json() # Response from the Request
    
    # Get Service ID for the request to Add Target(s) 
    targetRequestURL = responseBodyServiceRoute["data"]["id"]

    print(f'\nRoute {ROUTE_NAME["name"]} added. ')

    # Request to Add Target - provide the Route id and Target ID in a json
    reqTarget = req.request('POST',KONG_URL + targetRequestURL + '/targets',json= TARGET)
    
